css:
@page{

        size : 100mm 38mm;
        margin : 0;

}

html,body{
    margin:0;
    padding:0;
}

.print-format{
    margin:0 !important;
    padding:0 !important;
}

.label-table{
    width:100%;
    border-collapse:collapse;
    table-layout:fixed;
}

.label-table td{

    width:50mm;
    height:38mm;

    padding:0;
    vertical-align:top;

}

.label{

    width:49mm;
    height:37mm;

    /*padding:1mm;*/
    padding:0px!important;
    overflow:hidden;

    box-sizing:border-box;
    /*text-align:left!important;*/
    /*margin-left:1px!important;*/

}

.details{

    font-size:8px;

    line-height:1.50;

}

.barcode-container{
    text-align:center;
    margin-top:1mm;
}

.barcode-container img{
    width:36mm;
    height:15mm;
    display:block;
    margin:auto;
}

*,
table,
tr,
td,
div {
    border: none !important;
    outline: none !important;
    box-shadow: none !important;
}

.label::before,
.label::after,
.print-format::before,
.print-format::after {
    content: none !important;
    display: none !important;
}
